/// Try to simplify a switch on a ucmp/scmp intrinsic.
/// ucmp/scmp returns -1, 0, or 1, representing LT, EQ, GT respectively.
/// If the switch has exactly 2 cases going to one destination and the default
/// going to another, we can convert it to a single icmp+branch.
static bool simplifySwitchOfCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
  // We need exactly 2 cases.
  if (SI->getNumCases() != 2)
    return false;

  // Check if the condition is a ucmp/scmp intrinsic.
  auto *CmpI = dyn_cast<CmpIntrinsic>(SI->getCondition());
  if (!CmpI)
    return false;

  // Get the two case values and their destinations.
  auto CaseIt = SI->case_begin();
  ConstantInt *CaseVal0 = CaseIt->getCaseValue();
  BasicBlock *Dest0 = CaseIt->getCaseSuccessor();
  ++CaseIt;
  ConstantInt *CaseVal1 = CaseIt->getCaseValue();
  BasicBlock *Dest1 = CaseIt->getCaseSuccessor();
  BasicBlock *DefaultDest = SI->getDefaultDest();

  // Both cases must go to the same destination for this optimization.
  if (Dest0 != Dest1)
    return false;

  // The default must go to a different destination.
  if (DefaultDest == Dest0)
    return false;

  // Get the case values as signed integers.
  int64_t Val0 = CaseVal0->getValue().getSExtValue();
  int64_t Val1 = CaseVal1->getValue().getSExtValue();

  // ucmp/scmp only returns -1, 0, or 1.
  // We expect exactly two of these three values in the cases.
  // The third value is the default.
  bool HasNegOne = (Val0 == -1) || (Val1 == -1);
  bool HasZero = (Val0 == 0) || (Val1 == 0);
  bool HasOne = (Val0 == 1) || (Val1 == 1);

  // We need exactly two of the three possible values.
  if (HasNegOne + HasZero + HasOne != 2)
    return false;

  // Determine the predicate based on which value is the default.
  CmpInst::Predicate Pred;
  if (!HasOne) {
    // Default is 1 (GT), cases are -1 and 0 (LT or EQ).
    // This is equivalent to checking if LHS > RHS.
    Pred = CmpI->getGTPredicate();
  } else if (!HasNegOne) {
    // Default is -1 (LT), cases are 0 and 1 (EQ or GT).
    // This is equivalent to checking if LHS < RHS.
    Pred = CmpI->getLTPredicate();
  } else {
    // Default is 0 (EQ), cases are -1 and 1 (LT or GT).
    // This is equivalent to checking if LHS == RHS.
    Pred = ICmpInst::ICMP_EQ;
  }

  Builder.SetInsertPoint(SI);
  Value *Cmp = Builder.CreateICmp(Pred, CmpI->getLHS(), CmpI->getRHS(), "cmp");
  Builder.CreateCondBr(Cmp, DefaultDest, Dest0);

